@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.wrap {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.card {
  background: #fff;
  border-radius: 10px;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  padding: 20px 22px;
}

.card-title {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 14px;
}

/* Quick Links - slim bar */
.quicklinks-card {
  display: flex;
  align-items: center;
  gap: 20px;
  padding: 14px 22px;
  flex-wrap: wrap;
}

.quicklinks-buttons {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.quicklinks-title {
  font-size: 13px;
  font-weight: 700;
  color: #05042E;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  white-space: nowrap;
}

.btn {
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 700;
  padding: 0 16px;
  height: 38px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  white-space: nowrap;
  display: inline-flex;
  align-items: center;
  gap: 8px;
}

.btn-customer {
  background: #A3E851;
  color: #05042E;
}

.btn-customer:hover {
  background: #5DC987;
}

.btn-job {
  background: #469BC0;
  color: #fff;
}

.btn-job:hover {
  background: #1B4F6C;
}

.btn-sale {
  background: #FAEEDA;
  color: #633806;
}

.btn-sale:hover {
  background: #f5deb0;
}

.search-card {
  min-width: 0;
}

.search-grid {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.search-group {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.search-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.search-input {
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 500;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 9px 10px;
  outline: none;
  width: 100%;
}

.search-input:focus {
  border-color: #469BC0;
}

.search-hint {
  font-size: 10px;
  color: #888780;
  margin-top: 3px;
}

/* Two-column layout */
.grid-2 {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  text-align: left;
  padding: 8px 4px;
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

td {
  padding: 9px 4px;
  font-size: 12px;
  font-weight: 600;
  color: #05042E;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
}

tr:last-child td {
  border-bottom: none;
}

.empty {
  text-align: center;
  padding: 20px;
  color: #888780;
  font-size: 12px;
  font-weight: 500;
