.stat-count {
  font-size: 16px;
  font-weight: 700;
  color: #05042E;
}

.stat-sub {
  font-size: 10px;
  color: #888780;
  font-weight: 500;
}

.attention-badge {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
