.icon-green {
  background: #E1F5EE;
}

.icon-amber {
  background: #FAEEDA;
}

.icon-navy {
  background: rgba(5, 4, 46, 0.08);
}

.icon-grey {
  background: rgba(5, 4, 46, 0.05);
}

.activity-title {
  font-size: 12px;
  font-weight: 700;
  color: #05042E;
