function fmtNow() {
  var now = new Date();
  return now.toLocaleDateString('en-GB',{weekday:'long',day:'2-digit',month:'long',year:'numeric'}) + ' · ' + now.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});
}

function fmtRelative(d) {
  if (!d) return '—';
  var then = new Date(d);
  var diffMs = Date.now() - then.getTime();
  var mins = Math.floor(diffMs / 60000);
  if (mins < 1) return 'Just now';
  if (mins < 60) return mins + 'm ago';
  var hrs = Math.floor(mins / 60);
  if (hrs < 24) return hrs + 'h ago';
  var days = Math.floor(hrs / 24);
  return days + 'd ago';
}

function roleClass(role) {
  var map = { admin:'role-admin', manager:'role-manager', technician:'role-technician', viewer:'role-viewer' };
  return map[(role||'').toLowerCase()] || 'role-viewer';
}

var ACTIVITY_ICONS = {
  collection: '📅', customer: '👤', asset: '💻', asset_status_change: '💻',
  sale_pallet: '🛒', sale_pallet_created: '🛒', sale_pallet_closed: '✅',
  waste_pallet: '🗑️', waste_pallet_created: '🗑️', waste_pallet_closed: '✅'
};

var ACTIVITY_COLORS = {
  collection: 'icon-blue', customer: 'icon-blue', asset: 'icon-navy', asset_status_change: 'icon-navy',
  sale_pallet: 'icon-green', sale_pallet_created: 'icon-green', sale_pallet_closed: 'icon-green',
  waste_pallet: 'icon-amber', waste_pallet_created: 'icon-amber', waste_pallet_closed: 'icon-green'
};

function activityLabel(row) {
  var map = {
    collection: 'Collection — ' + (row.title_detail || '—'),
    customer: 'New Customer — ' + (row.title_detail || '—'),
    asset: 'Asset ' + (row.status || 'updated') + ' — ' + (row.title_detail || '—'),
    asset_status_change: 'Asset ' + (row.status || 'updated') + ' — ' + (row.title_detail || '—'),
    sale_pallet: 'Sale Pallet — ' + (row.title_detail || '—'),
    waste_pallet: 'Waste Pallet — ' + (row.title_detail || '—'),
    sale_pallet_created: 'Sale Pallet Created — ' + (row.title_detail || '—'),
    sale_pallet_closed: 'Sale Pallet Closed — ' + (row.title_detail || '—'),
    waste_pallet_created: 'Waste Pallet Created — ' + (row.title_detail || '—'),
    waste_pallet_closed: 'Waste Pallet Closed — ' + (row.title_detail || '—')
  };
  return map[row.activity_type] || (row.title_detail || 'Activity');
}

function renderActivityList(elId, rows, limit) {
  var el = document.getElementById(elId);
  if (!rows || !rows.length) { el.innerHTML = '<div class="empty">No recent activity</div>'; return; }
  var list = limit ? rows.slice(0, limit) : rows;
  el.innerHTML = list.map(function(r) {
    var colorClass = ACTIVITY_COLORS[r.activity_type] || 'icon-grey';
    return '<div class="activity-row">' +
      '<div class="activity-icon ' + colorClass + '">' + (ACTIVITY_ICONS[r.activity_type] || '•') + '</div>' +
      '<div><div class="activity-title">' + escHtml(activityLabel(r)) + '</div>' +
      '<div class="activity-meta">' + escHtml(r.created_by || '—') + '</div></div>' +
      '<div class="activity-time">' + fmtRelative(r.created_at) + '</div>' +
      '</div>';
  }).join('');
}

function renderBreakdown(rows) {
  var tbody = document.getElementById('breakdown_body');
  if (!rows || !rows.length) { tbody.innerHTML = '<tr class="empty"><td colspan="4">No data</td></tr>'; return; }
  tbody.innerHTML = rows.map(function(r) {
    return '<tr><td>' + escHtml(r.item_type_name) + '</td><td>' + (r.total||0) + '</td><td>' + (r.this_month||0) + '</td><td>' + (r.this_year||0) + '</td></tr>';
  }).join('');
}

function renderSla(rows) {
  var el = document.getElementById('sla_body');
  if (!rows || !rows.length) { el.innerHTML = '<div class="empty">No breaches — all collections on track ✓</div>'; return; }
  el.innerHTML = rows.map(function(r) {
    var days = Math.floor(r.business_days_elapsed || 0);
    var badgeClass = days > 15 ? 'badge-danger' : 'badge-warn';
    return '<div class="activity-row">' +
      '<div class="activity-icon">⚠️</div>' +
      '<div><div class="activity-title">Collection #' + r.collection_id + ' — ' + escHtml(r.job_type || '—') + '</div>' +
      '<div class="activity-meta">' + escHtml(r.created_by || '—') + ' · ' + escHtml(r.status || '—') + '</div></div>' +
      '<span class="attention-badge ' + badgeClass + '" style="margin-left:auto;">' + days + 'd overdue</span>' +
      '</div>';
  }).join('');
}

function render(model) {
  var m = model || {};

  // Breakdown
  renderBreakdown(m.assetBreakdown || []);

  // Activity
  renderActivityList('activity_body', m.activity || [], 8);

  // My activity
  renderActivityList('my_activity_body', m.myActivity || [], 10);

  // Ops alerts
  renderOpsAlerts(m.opsAlerts || []);

  // Open pallets
  var op = (m.openPallets && m.openPallets[0]) || {};
  document.getElementById('open_sale_count').textContent = op.open_sale_pallets || 0;
  document.getElementById('open_waste_count').textContent = op.open_waste_pallets || 0;

  // SLA
  renderSla(m.slaBreaches || []);
}

function wireEvents() {
  document.getElementById('btn_new_customer').addEventListener('click', function() { appsmith.triggerEvent('onGoCreateCustomer'); });
  document.getElementById('btn_new_job').addEventListener('click', function() { appsmith.triggerEvent('onGoCreateJob'); });
  document.getElementById('btn_new_sale').addEventListener('click', function() { appsmith.triggerEvent('onGoNewSale'); });

  function showSearchError(msg) {
    document.getElementById('search_error').textContent = msg || '';
  }

  document.getElementById('search_asset_ref').addEventListener('keydown', function(e) {
    if (e.key !== 'Enter') return;
    var val = this.value.trim();
    if (!val) return;
    showSearchError('');
    appsmith.updateModel({ searchQuery: val, searchField: 'asset_ref' });
    appsmith.triggerEvent('onSearchAssetRef');
  });

  document.getElementById('search_serial').addEventListener('keydown', function(e) {
    if (e.key !== 'Enter') return;
    var val = this.value.trim();
    if (!val) return;
    showSearchError('');
    appsmith.updateModel({ searchQuery: val, searchField: 'serial' });
    appsmith.triggerEvent('onSearchSerial');
  });

  document.getElementById('search_collection').addEventListener('keydown', function(e) {
    if (e.key !== 'Enter') return;
    var val = this.value.trim();
    if (!val) return;
    showSearchError('');
    appsmith.updateModel({ searchQuery: val, searchField: 'collection' });
    appsmith.triggerEvent('onSearchCollection');
  });
}

function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function() {
    render(appsmith.model);
    wireEvents();
    appsmith.triggerEvent('onLoadMyActivity');
    appsmith.triggerEvent('onLoadOpsAlerts');
    appsmith.onModelChange(function(model) {
      render(model);
      if (model.searchErrorMessage) {
        document.getElementById('search_error').textContent = model.searchErrorMessage;
      }
    });
  });
}

initWhenReady();
